import { loadScript } from '../util';
import WechatH5 from './WechatH5.js';
import Xuetong from './Xuetong.js';
import Keycloak from './Keycloak.js';
import Unicom from './Unicom.js';
import Test from './Test.js';

const allHooks = [
    // 'beforeJump', 'jumpPass', 'codeLogin',
    // 'nuimsJumpPass', 'nuimsCodeLogin',
    // 'initDirectProduct', 'initDirectPlatform',
    'h5BeforeJump', 'h5JumpPass', 'h5CodeLogin',
    'h5NuimsJumpPass', 'h5NuimsCodeLogin', 'h5AfterLogin',
    'h5InitDirectProduct', 'h5InitDirectPlatform',
    'h5AfterLogin',
];
const pluginsMap = {};

createPlugin(WechatH5);
createPlugin(Xuetong);
createPlugin(Keycloak);
createPlugin(Unicom);
createPlugin(Test);

export function createPlugin(Plugin) {
    const instance = new Plugin();
    pluginsMap[instance.name] = {};
    allHooks.forEach((hook) => {
        if (instance[hook]) {
            pluginsMap[instance.name][hook] = instance[hook];
        }
    });
}

export function usePlugin(hookName, context, callback) {
    getAllPlugin().forEach((pluginName) => {
        if (context.loginType === pluginName) {
            if (!pluginsMap[pluginName][hookName]) {
                pluginsMap[pluginName][hookName] = (context, callback) => callback();
            }
            pluginsMap[pluginName][hookName](context, callback);
        }
    });
}

export function getAllPlugin(params) {
    return Object.keys(pluginsMap);
}

export function concatPluginList(list) {
    return [...new Set([...list, ...getAllPlugin()])];
}

const loadByKey = (key, value) => {
    if (window[key]) {
        return Promise.resolve();
    } else {
        if (Array.isArray(value)) {
            return Promise.all(value.map(loadScript));
        }
        return loadScript(value);
    }
};
export async function loadOneRemotePlugin(key, value) {
    if (key && value) {
        await loadByKey(key, value).then((plugin) => createPlugin(window[key]));
    }
}
export async function loadRemotePlugins(jsUrlList, currentKey) {
    await Promise.all(jsUrlList.filter((it) => it.JsUrl).map(async (item) => {
        if (item.Type && item.JsUrl) {
            await loadByKey(item.Type, item.JsUrl).then((plugin) => createPlugin(window[item.Type]));
        }
    }));
}
