<template>
    <div ref="div1" :class="$style.root" vusion-slot-name="default" v-show="enableUI">
       <div>
         <van-row ref="row1" :class="$style['login-title']">
            <!-- <van-text ref="text1" text="登录"></van-text> -->
            <span>登录</span>
        </van-row>
        <van-tabs v-if="tabs.length > 1" v-model="LoginType" appear="line" style="width: 38.4vw;margin-bottom: 4.2666vw">
            <van-tab
                :name="tab.name"
                v-for="tab in tabs"
                :key="tab.value"
                :title="tab.title"
                :value="tab.value"
            ></van-tab>
        </van-tabs>

        <van-form ref="form1" :class="$style['login-form']">
            <van-field ref="field1" :class="$style['login-cell']"
                v-model="AccountId" name="accountId" placeholder="请输入账号" rules="required">
                <template #left-icon>
                <!--   window.appInfo?.sysPrefixPath -->
                    <img ref="img1" :class="$style['account-left-icon']" :src="getPrefixPath('/assets/h5/account-icon.png')">
                </template>
            </van-field>
            <van-field ref="field2" :class="$style['login-cell']" v-model="AccountPassword" :type="passwordortext" name="accountPwd" placeholder="请输入密码" rules="required"
                eye="yes" @click-right-icon="field2_clickrighticon(event)">
                <template #left-icon>
                    <img ref="img2" :class="$style['account-left-icon']" :src="getPrefixPath('/assets/h5/pwd-icon.png')">
                </template>
            </van-field>
            <div ref="div2" style="margin-top: 8.53333vw">
                <van-button ref="button1" :class="$style['cus-login-button']" type="info" native-type="submit" @click="button1_click(event)">
                    登录
                </van-button>
            </div>
        </van-form>
       </div>
        <!-- 跳转登录 -->
        <div v-if="authTypes.length > 0" style="margin-bottom:32px;margin-top: 100px">
            <div :class="$style.dividerbox">
                <div :class="$style.divider"></div>
                <span style="margin:0 18px;font-size:12px">使用以下方式登录</span>
                <div :class="$style.divider"></div>
             </div>
            <div>
                <div :class="$style.linkbox" v-for="auth in authTypes" :key="auth.value">
                    <div
                        @click="jumpAuth(auth.value)"
                        :class="$style.link"
                    >{{ auth.title }}
                    </div>
                </div>
            </div>
        </div>

    </div>
</template>

<script>
// import VConsole from 'vconsole';
// const vConsole = new VConsole();
import queryString from 'query-string';
import { NUIMS_DOMAIN_NAME, getArr, getTenant, rmLastSlash, getObj, authKeyLoginType, AES_ECB_encrypt, parseToken } from './util';
import localService from './usercenter/service';
import tokenMethod from './token';
import service from './service';
import cookie from './cookie';
import { concatPluginList, usePlugin, loadRemotePlugins } from './plugin/index';

function noop() {
    return '';
}
const noSupport = {
    set: noop,
    get: noop,
    remove: noop,
    clear: noop,
};

const isLocalStorageAvailable = () => {
    try {
        const key = 'testlocastorage';
        window.localStorage.setItem(key, '1');
        window.localStorage.removeItem(key);

        return true;
    } catch (error) {
        return false;
    }
};

const storage = isLocalStorageAvailable() ? window.localStorage : null;
const storageUtil = !storage ? noSupport : {
    set(key, value) {
        storage.setItem(key, value);
    },
    get(key) {
        return storage.getItem(key);
    },
    remove(key) {
        return storage.removeItem(key);
    },
    clear() {
        storage.clear();
    },
};

function getDomain() {
    const { hostname } = location;
    const hostArr = hostname.split('.');
    if (hostArr.length < 3)
        return hostname;
    const len = hostArr.length;
    return `${hostArr[len - 3]}.${hostArr[len - 2]}.${hostArr[len - 1]}`;
}
let token;
const cookieUtil = {
    set(data = {}, exdays = 1) {
        const d = new Date();
        d.setTime(d.getTime() + exdays * 24 * 60 * 60 * 1000);
        const expires = d.toGMTString();
        Object.keys(data).forEach((key) => {
            const value = data[key];
            if (key && value) {
                document.cookie = `${key}=${encodeURIComponent(
                    value,
                )}; expires=${expires}; path=/`;
            }
        });
    },
    get(name) {
        const nameEQ = name + '=';
        const ca = document.cookie.split(';');
        for (let i = 0; i < ca.length; i++) {
            let c = ca[i];
            while (c.charAt(0) === ' ')
                c = c.substring(1, c.length);
            if (c.indexOf(nameEQ) === 0)
                return decodeURIComponent(c.substring(nameEQ.length, c.length));
        }
        return null;
    },
    erase(name) {
        const d = new Date();
        d.setTime(d.getTime() - 1 * 24 * 60 * 60 * 1000);
        const expires = d.toGMTString();
        document.cookie = `${name}=; expires=${expires}; path=/`;
        const domain = getDomain();
        document.cookie = `${name}=; expires=${expires}; path=/; domain=${domain}`;
    },
    eraseAll() {
        const cookies = document.cookie.split(';');
        for (let i = 0; i < cookies.length; i++) {
            const cookie = cookies[i];
            const eqPos = cookie.indexOf('=');
            const name = eqPos > -1 ? cookie.substr(0, eqPos) : cookie;
            this.erase(name);
        }
    },
};
// eslint-disable-next-line no-unused-vars
const tokenUtil = {
    set(Authorization) {
        token = Authorization;
        cookieUtil.set({ authorization: Authorization });
        storageUtil.set('Authorization', Authorization);
    },
    get() {
        return (
            token
            || cookieUtil.get('authorization')
            || storageUtil.get('Authorization')
        );
    },
    erase() {
        this.set('');
        cookieUtil.eraseAll();
    },
};

// const getTenant = () => {
// 制品的租户标记
// return localStorage.getItem('tenant')|| window?.appInfo?.tenant || 'defaulttenant'
// let _window; let _window$appInfo;
// return localStorage.getItem('tenant')
//     // eslint-disable-next-line
//     || ((_window = window) === null || _window === void 0
//      ? void 0
//      : (_window$appInfo = _window.appInfo) === null || _window$appInfo === void 0 ? void 0 : _window$appInfo.tenant)
//     || 'defaulttenant';
// };

let appinfoEnv; let src;
if (window?.appInfo?.env) {
    appinfoEnv = window.appInfo.env;
}
if (window?.appInfo?.nuimsDomain) {
    const tenant = getTenant();
    const tenantUri = `${tenant}.`;
    src = `${location.protocol}//dev.${tenantUri}${window.appInfo.nuimsDomain}`;
}
const isPlatform = (text) => ['LowcodePlatform', 'PermissionCenter'].includes(text);
// 如果在iframe中会拒绝访问，需要使用parent.location
const customLocation = window.parent?.location || location;
export default {
    name: 'lcap-h5-login',
    components: {
    },
    props: {
        scene: {
            type: String,
            default: '',
        },
        displayMode: {
            type: Boolean,
            default: false,
        },
        useRedirect: {
            type: Boolean,
            default: true,
        },
        mainLoginTypes: {
            type: Array,
            default: () => [],
        },
        redirectLoginTypes: {
            type: Array,
            default: () => [],
        },
        subLoginTypes: {
            type: Array,
            default: () => [],
        },
        // 账号认证与权限中心域名
        src: {
            type: String,
            default: '',
        },
        // 账号认证与权限中心请求相对路径
        nuimsUrl: {
            type: String,
            default: '/gateway/nuims/nuims',
        },
        // 账号认证与权限中心环境信息
        env: {
            type: String,
            default: '',
        },
        // 租户名称
        tenantName: String,
        // 登录应用名称
        domainName: String,
        // 开启普通登录，默认开启
        useNormal: {
            type: Boolean,
            default: true,
        },
        usePopo: {
            type: Boolean,
            default: false,
        },
        useUnicom: {
            type: Boolean,
            default: false,
        },
        useXuetong: {
            type: Boolean,
            default: false,
        },
        useKeycloak: {
            type: Boolean,
            default: false,
        },
        useWechatH5: {
            type: Boolean,
            default: false,
        },
        exdays: {
            type: Number,
            default: 1,
        },
        // 开启在制品里面的登录
        hasUserCenter: {
            type: Boolean,
            default: false,
        },
    },
    data() {
        return {
            // enableUI: true,
            eye: false,
            passwordortext: 'password',
            LoginType: 'Normal',
            AccountId: '',
            AccountPassword: '',
            // 租户级别基础登录配置
            tenantLoginTypesLoading: true,
            tenantLoginTypes: [],
            AppKeyMap: {},
            // 组件登录配置
            configLoading: true,
            configLoginTypes: ['Normal'],
            isUnicom: false,
            // ---------------- account 可能需要调整 tabs authTypes没有展示的样式
            jsUrls: {},
            isDirectNoUI: false,
            loading: true,
            account: {
                LoginType: 'Normal',
                AccountId: '',
                AccountPassword: '',
                isplugin: false,
            },
            AuthConfigMap: {},
            tabs: [],
            authTypes: [
            ],
            hasTabLoginTypes: true,
            showNoneTips: false,
            showPassword: false,
            errMsg: '',
            accountRule: ['required'],
            pwdRule: ['required | minLength(8)'],
            low: this.hasUserCenter, // 控制下沉模式（制品应用内部登录） 还是 集中模式（nuims集中登录）
            compType: localStorage.getItem('compType'),
        };
    },
    computed: {
        indexPage() {
            let url = '/';
            if (window.appInfo.basePath) {
                url = `${window.appInfo.basePath}/`;
            }
            return url;
        },
        // passSrc() {
        //     const nuimsDomain = window.appInfo.nuimsDomain;
        //     const tenantUri = getTenant();
        //     const src = `${window.location.protocol}//dev.${tenantUri}.${nuimsDomain}`;
        //     return `${rmLastSlash(src)}`;
        // },
        isIDE() {
            return this?.$env?.VUE_APP_DESIGNER;
        },
        enableUI() {
            if (this.isIDE) {
                return true;
            }
            return this.useRedirect;
        },
        isProductApp() {
            if (this.isIDE) {
                return false;
            }
            return window.appVue;
        },
        fnEnv() {
            if (this.isProductApp)
                return window?.appInfo?.env;
            return window?.appInfo?.platformEnv || this.env;
        },
        passSrc() {
            if (this.isProductApp) {
                if (window?.appInfo?.nuimsDomain) {
                    const tenant = getTenant();
                    const tenantUri = `${tenant}.`;
                    if (window?.appInfo?.env && window?.appInfo?.env === 'online') {
                        src = `${location.protocol}//${tenantUri}${window.appInfo.envNuimsDomain.online}`;
                    } else {
                        src = `${location.protocol}//dev.${tenantUri}${window.appInfo.envNuimsDomain.dev}`;
                    }
                }
                return `${rmLastSlash(src)}`;
            }
            if (this.scene === 'LowcodePlatform') {
                if (window?.appInfo?.nuimsDomain) {
                    const tenant = getTenant();
                    const tenantUri = `${tenant}.`;
                    const platformEnv = window?.appInfo?.platformEnv;
                    if (platformEnv === 'online') {
                        src = `${location.protocol}//${tenantUri}${window.appInfo.nuimsDomain}`;
                    } else {
                        src = `${location.protocol}//dev.${tenantUri}${window.appInfo.nuimsDomain}`;
                    }
                }
                return `${rmLastSlash(src)}`;
            }
            return `${rmLastSlash(this.src)}`;
        },
    },
    watch: {
        useRedirect(val) {
            // 在ide里 即使关闭UI按钮 也要展示 UI
            if (this.isIDE && !val) {
                setTimeout(() => {
                    this.resetToDefault();
                }, 500);
            }
        },
        mainLoginTypes(val) {
            (isPlatform(this.scene) || this.isIDE) && this.initUI(this.mainLoginTypes, this.subLoginTypes, this.redirectLoginTypes);
        },
        subLoginTypes(val) {
            (isPlatform(this.scene) || this.isIDE) && this.initUI(this.mainLoginTypes, this.subLoginTypes, this.redirectLoginTypes);
        },
        redirectLoginTypes(val) {
            (isPlatform(this.scene) || this.isIDE) && this.initUI(this.mainLoginTypes, this.subLoginTypes, this.redirectLoginTypes);
        },
    },
    async mounted() {
        this.low = window?.appInfo?.hasUserCenter || false;
        if (this.displayMode) {
            this.loading = false;
            return;
        }
        const { search } = location;
        const query = queryString.parse(search);
        let { loginType, code, authToken, redirect, userName, userId, token, authKey, externalSystem, span, shufanAuthPageUrl, loginSuccessUrl } = query;
        loginType = localStorage.getItem('LoginType') || cookie.get('LoginType') || loginType;
        if (!this.isIDE) {
            await this.loadRemote();
        }
        if (this.compType === 'pass') {
            // 制品应用不应该 走接口
            if (this.isProductApp) {
                await this.initProductAppUI('pass');
            } else {
                await this.getTenantConfig();
            }
            try {
                this.jumpAuthPass();
            } catch (error) {
                console.error('error: ', error);
                localStorage.setItem('compType', '');
            }
        } else if (this.compType === 'cb') {
            localStorage.setItem('compType', '');
            try {
                if (this.isProductApp) {
                    await this.initProductAppUI('cb');
                } else {
                    await this.getTenantConfig();
                }
                await this.codeLogin(query);
            } catch (error) {
                location.reload();
                console.error('error: ', error);
            }
        } else {
            if (authToken && redirect) {
                cookie.set({ authorization: authToken });
                this.$emit('success', {
                    Authorization: authToken,
                });
                customLocation.href = redirect;
            } else if (token) {
                // 对返回结果只包含 token 的解析方式，，目前主要是对接学同的场景
                cookie.set({ authorization: token });
                this.$emit('success', {
                    Authorization: token,
                });
                if (window.appVue) {
                    customLocation.href = this.indexPage;
                }
            } else if (userName && userId && code) {
                const cookieUserInfo = parseToken(code);
                if (cookieUserInfo.AuthTypeTokenExpire) {
                    cookie.set({ authorization: code }, 15);
                } else {
                    cookie.set({ authorization: code });
                }
                let href = loginSuccessUrl || this.indexPage;
                if (loginSuccessUrl) {
                    // emit success 到低代码平台时无法带参 这里直接截断跳转吧
                    customLocation.href = loginSuccessUrl;
                    return;
                }
                // const loginType = localStorage.getItem('LoginType') || cookie.get('LoginType');
                if (['Shufan', 'CShufan'].includes(loginType)) {
                    const shufanPage = localStorage.getItem('shufanPage');
                    tokenMethod.set(code);
                    localStorage.setItem('LoginType', 'Other');
                    cookie.set({ LoginType: 'Other' });
                    if (shufanPage) {
                        customLocation.href = shufanPage;
                        return;
                    }
                }
                const context = {
                    loginType,
                    Authorization: code,
                    UserName: userName,
                    UserId: userId,
                };
                const callback = (hrefCb) => {
                    if (hrefCb) {
                        href = hrefCb;
                    }
                };
                usePlugin('h5AfterLogin', context, callback);
                this.$emit('success', {
                    Authorization: code,
                    UserName: userName,
                    UserId: userId,
                    href,
                });

                if (window.appVue && !this.$listeners.success) {
                    customLocation.href = href;
                }
            } else if (authKeyLoginType.includes(externalSystem)) {
                await service.ExternalSystemLogin({
                    url: this.nuimsUrl,
                    body: {
                        externalSystem,
                        data: {
                            authKey,
                        },
                    },
                });

                const Token = tokenMethod.get();
                if (Token) {
                    this.jumpSuccess(Token);
                }
            } else if (span && span === 'shufan_nologin') {
                try {
                    cookie.erase('authorization');
                    const res = await service.NuimsLogin({
                        url: this.nuimsUrl,
                        body: {
                            LoginType: 'Shufan',
                            TenantName: this.tenantName || getTenant(),
                            DomainName: NUIMS_DOMAIN_NAME,
                        },
                    });
                    const Token = res?.headers?.authorization;
                    if (Token) {
                        cookie.set({ authorization: Token });
                        customLocation.href = `/sso?token=${Token}`;
                    }
                } catch (error) {
                    if (+error.status === 403) {
                        customLocation.href = shufanAuthPageUrl;
                    }
                }
            } else {
                if (this.isProductApp) {
                    // 制品应用 从nasl 获取 数据
                    await this.initProductAppUI();
                    this.loading = false;
                } else if (isPlatform(this.scene) || this.isIDE) {
                    // 平台应用 从接口 获取 数据
                    await this.getTenantConfig();
                }
            }
        }
    },
    methods: {
        getPrefixPath(path){
            return `${window.appInfo.sysPrefixPath ||''}${path}`
        },
        async field2_clickrighticon(event) {
            await this.__clickRightIcon(event);
        },
        async button1_click(event) {
            await this.__onSubmit(event);
        },
        __clickRightIcon() {
            const now = this.passwordortext;
            if (now === 'password') {
                this.passwordortext = 'text';
            } else {
                this.passwordortext = 'password';
            }
        },
        __onSubmit() {
            this.login();
        },
        // ---------------------
        async loadRemote() {
            // 特殊处理下popo插件 会和小程序冲突 : 当选中Popo登录的时候才加载Popo插件 否则不加载
            // 目前的策略是全量加载
            // this.redirectLoginTypes[0].name==="Popo"
            // let filterList = [];
            // if (this.redirectLoginTypes[0]?.name === 'Popo') {
            //     filterList = ['Popo'];
            // }
            let jsUrls;
            const getResData = (res) => getArr(getObj(getObj(res).data).Data);
            const formatJsUrl = (list) => getResData(list).filter((it) => it.extendProperties)
                .map((it) => ({ JsUrl: it.extendProperties?.authJsUrl?.replace(/^https?:/i, ''), Type: it.LoginType }));
            // .filter((it) => !filterList.includes(it.Type));
            if (this.low) {
                const res = await localService.getTenantLoginTypes({});
                const Data = getObj(getObj(res).data).Data;
                jsUrls = Object.keys(Data).map((key) => {
                    const it = Data[key];
                    if (it && it.config && it.config.authJsUrl) {
                        return {
                            JsUrl: it.config.authJsUrl,
                            Type: key,
                        };
                    } else {
                        return { JsUrl: '', Type: '' };
                    }
                });
            } else {
                debugger
                console.log(' this.nuimsUrl99: ',  this.nuimsUrl);
                const p = {
                    // todo: sysPrefixPath 好像是这里 统一前缀不生效 debugger
                    url: this.nuimsUrl,
                    params: {
                        TenantName: this.tenantName || getTenant(),
                        Scope: 'h5',
                    },
                };
                if (this.env) {
                    p.headers = {
                        Env: this.env,
                    };
                }
                const res = await service.getTenantLoginTypes(p);
                jsUrls = formatJsUrl(res);
            }
            await loadRemotePlugins(jsUrls);
        },
        resetToDefault() {
            this.tabs = [{
                title: '普通登录',
                value: 'Normal',
            }];
            this.authTypes = [];
        },
        initProductAppUI(scene) {
            const format = (item) => ({
                value: item.name,
                ...item,
            });
            this.tabs = this.mainLoginTypes.filter((item) => item.default).map(format);
            this.authTypes = this.subLoginTypes.filter((item) => item.default).map(format);
            const direct = this.redirectLoginTypes[0];
            if (!this.mainLoginTypes || this.mainLoginTypes?.length <= 0) {
                this.resetToDefault();
            }
            this.defaultFocus();
            if (direct && !this.useRedirect) {
                this.isDirectNoUI = true;
                const context = {
                    localService, low: this.low,
                    indexPage: this.indexPage,
                    loginType: direct.name,
                    service, scene,
                    query: queryString.parse(location.search),
                    jumpAuthFn: this.jumpAuth,
                    compType: this.compType,
                    cookieUitl: cookie,
                    nuimsUrl: this.nuimsUrl,
                    TenantName: this.tenantName || getTenant(),
                    DomainName: NUIMS_DOMAIN_NAME,
                };
                const callback = (userInfoCb, hrefCb) => {
                    if (userInfoCb) {
                        const { authorization, UserName, UserId } = userInfoCb;
                        cookie.set({ authorization,
                                     userName: UserName,
                                     userId: UserId });
                        this.$emit('success', { Authorization: authorization, UserName, UserId });
                        customLocation.href = hrefCb || this.indexPage;
                    } else {
                        if (direct.name && !scene) {
                            this.jumpAuth(direct.name);
                        }
                    }
                };
                usePlugin('h5InitDirectProduct', context, callback);
            }
        },
        initUI(mainLoginTypes, subLoginTypes, redirectLoginTypes) {
            const isActive = (item) => item.default === true;
            this.tabs = mainLoginTypes.filter(isActive).map((it) => ({
                ...it,
                value: it?.name?.replace('use', ''),
            }));
            this.authTypes = subLoginTypes.filter(isActive);
            const obj = this.authTypes.find((item) => (item.value === 'Keycloak'));
            if (obj && !this.displayMode) {
                this.jumpAuth('Keycloak');
            }
            if (this.isIDE && !this.useRedirect) {
                this.resetToDefault();
            }
            const direct = redirectLoginTypes[0];
            let useDirect = direct;
            if (this.isProductApp) {
                useDirect = direct && !this.useRedirect;
            }
            if (useDirect) {
                this.isDirectNoUI = true;
                if (direct.value) {
                    this.jumpAuth(direct.value);
                }

                const context = {
                    loginType: direct.value,
                    service,
                    query: queryString.parse(location.search),
                    jumpAuthFn: this.jumpAuth,
                    compType: this.compType,
                    cookieUitl: cookie,
                    nuimsUrl: this.nuimsUrl,
                    TenantName: this.tenantName || getTenant(),
                    DomainName: NUIMS_DOMAIN_NAME,
                };
                const callback = (userInfoCb, hrefCb) => {
                    if (userInfoCb) {
                        const { authorization, UserName, UserId } = userInfoCb;
                        cookie.set({ authorization,
                                     userName: UserName,
                                     userId: UserId });
                        this.$emit('success', { Authorization: authorization, UserName, UserId });
                        customLocation.href = hrefCb || this.indexPage;
                    }
                };
                usePlugin('h5InitDirectPlatform', context, callback);
            }
            if (this.displayMode && this.tabs.length > 0) {
                this.account.LoginType = this.tabs[0].value;
            }
        },
        async getTenantConfig() {
            let authTypes = [];
            if (this.isIDE) {
                this.initUI(this.mainLoginTypes, this.subLoginTypes, this.redirectLoginTypes);
                if (this.tabs.length <= 0) {
                    this.tabs = [{
                        title: '普通登录',
                        value: 'Normal',
                    }];
                    authTypes = [];
                }
            } else {
                try {
                    let res;
                    if (this.low) {
                        res = await localService.getTenantLoginTypes({
                        });
                    } else {
                        const p = {
                            url: this.nuimsUrl,
                            params: { TenantName: this.tenantName || getTenant() },
                        };
                        if (this.env) {
                            p.headers = {
                                Env: this.env,
                            };
                        }
                        // res = await service.getTenantLoginTypes({
                        res = await service.GetTenantSortedLoginTypes(p);
                    }

                    const format = (item) => ({
                        title: item.LoginLabel,
                        name: item.LoginType,
                        value: item.LoginType,
                        default: true,
                        plugin: item.Plugin,
                    });
                    const resData = getObj(getObj(getObj(res).data).Data);

                    const mainLoginTypes = resData.Main.map(format);
                    authTypes = resData.Sub.map(format);
                    const redirectLoginTypes = resData.Direct.map(format);
                    this.initUI(mainLoginTypes, authTypes, redirectLoginTypes);
                } catch (error) {
                    console.info(error);
                    authTypes = [];
                }
            }
            if (this.tabs.length > 0) {
                this.account.LoginType = this.tabs[0].value;
            } else {
                this.hasTabLoginTypes = false;
                if (authTypes.length === 1) {
                    // 当有且仅有一种 Auth 登录时，直接登录
                    this.jumpAuth(authTypes[0].value);
                } else if (authTypes.length === 0) {
                    this.showNoneTips = true;
                }
            }
            this.loading = false;
        },

        jumpSuccess(token) {
            cookie.set({ authorization: token });
            this.$emit('success', {
                Authorization: token,
            });
            if (window.appVue) {
                customLocation.href = this.indexPage;
            }
        },
        //  处理跳转返回的 code
        async codeLogin(query) {
            const { code, userName, redirect, userId } = query;
            // 其他应用单点登录跳转
            if (userName && userId && code) {
                const cookieUserInfo = parseToken(code);
                if (cookieUserInfo.AuthTypeTokenExpire) {
                    tokenMethod.set(code, 15);
                } else {
                    tokenMethod.set(code);
                }
                localStorage.setItem('LoginType', 'Other');
                cookie.set({ LoginType: 'Other' });
                customLocation.href = redirect ? decodeURIComponent(redirect) : `/`;
            } else {
                // Auth 登录中转页
                const LoginType = localStorage.getItem('LoginType') || cookie.get('LoginType');
                const RedirectUri = localStorage.getItem('RedirectUri') || cookie.get('RedirectUri');
                let params = {
                    Code: code,
                    RedirectUri,
                    OAuthLoginType: 'Netease',
                    TenantName: getTenant(),
                    DomainName: NUIMS_DOMAIN_NAME,
                };
                const allLoginTypes = [...this.tabs, ...this.authTypes, ...this.redirectLoginTypes];
                const isplugin = allLoginTypes.find((item) => item.value === LoginType.slice(1))?.plugin;

                let currentService;
                if (this.low) {
                    currentService = localService;
                } else {
                    currentService = service;
                }
                let oAuthService = currentService.OauthLogin;
                if (isplugin) {
                    oAuthService = currentService.NuimsLogin;
                }

                if (this.low) {
                    oAuthService = localService.login;
                }
                if (LoginType === 'lowcode_aam' || LoginType === 'Clowcode_aam') {
                    // 工行登陆
                    const { SSIAuth, SSISign } = query;
                    params = {
                        SsiAuth: SSIAuth,
                        SsiSign: SSISign,
                        LoginType: 'lowcode_aam',
                        TenantName: getTenant(),
                        DomainName: NUIMS_DOMAIN_NAME,
                    };
                }

                const context = {
                    low: this.low,
                    query: queryString.parse(location.search),
                    loginType: LoginType.slice(1),
                    queryString,
                };
                const callback = (paramsCb) => {
                    if (paramsCb) {
                        params = { ...params, ...paramsCb };
                    } else {
                        // customLocation.href = decodeURIComponent(authObj.toString());
                    }
                };
                usePlugin('h5CodeLogin', context, callback);
                try {
                    let res;
                    if (this.low) {
                        // 请求制品的接口
                        res = await oAuthService({
                            data: {
                                ...params,
                                LoginType: LoginType.slice(1),
                            },
                        });
                        res = res.data;
                    } else if (isplugin) {
                        const pluginParams = {
                            url: this.nuimsUrl,
                            body: {
                                ...params,
                                Code: code,
                                RedirectUri,
                                LoginType: LoginType.slice(1),
                                TenantName: this.tenantName || getTenant(),
                                DomainName: NUIMS_DOMAIN_NAME,
                            },
                        };
                        res = await oAuthService(pluginParams);
                        res = res.data;
                    } else {
                        res = await oAuthService({
                            url: this.nuimsUrl,
                            body: params,
                        });
                    }

                    const { Data } = getObj(res);
                    const { UserName, UserId, userName, userId } = getObj(Data);
                    let href;
                    // 登录组件通过 Auth 登录中转页
                    const pluginList = ['Github', 'Wechat', 'lowcode_aam',
                                        'lowcode_aam', 'Taikang', 'Shufan'];
                    if (concatPluginList(pluginList).includes(LoginType.slice(1))) {
                        href = decodeURIComponent(
                            redirect || localStorage.getItem('From') || cookie.get('From'),
                        );
                        const Token = tokenMethod.get();
                        const Back = `${href}${
                            href.includes('?') ? '&' : '?'
                        }userName=${UserName || userName}&userId=${UserId || userId}&code=${Token}`;
                        href = Back;
                    } else {
                        href = redirect ? decodeURIComponent(redirect) : `${origin}`;
                    }
                    // eslint-disable-next-line require-atomic-updates
                    customLocation.href = href;
                } catch (error) {
                    console.error('error: ', error);
                    const { message } = error || {};
                    if (message && message.includes('The user is not bound')) {
                        customLocation.href = '/403';
                    } else {
                        location.reload();
                        this.$toast.show({
                            message,
                            position: 'top',
                        });
                    }
                }
            }
        },
        defaultFocus() {
            if (this.tabs.length > 0) {
                this.account.LoginType = this.tabs[0].value;
            } else {
                this.hasTabLoginTypes = false;
                if (this.authTypes.length === 1) {
                    // 当有且仅有一种 Auth 登录时，直接登录
                    this.jumpAuth(this.authTypes[0].value);
                } else if (this.authTypes.length === 0) {
                    this.showNoneTips = true;
                }
            }
        },

        async login() {
            let errMsg;
            try {
                errMsg = '';
                // await this.$refs.accValidator.validate();
                // await this.$refs.pwdValidator.validate();
                // const { AccountId, AccountPassword, LoginType } = this.account;
                const { AccountId, AccountPassword, LoginType } = this;
                if (!(AccountId.length > 0 && AccountPassword.length > 0)) {
                    return;
                }
                // const context = {
                //     low: this.low,
                //     cookie,
                //     loginType: LoginType,
                //     fnEnv: this.fnEnv,
                //     AccountId,
                //     AccountPassword,
                // };
                // let isEnd = false
                // const callback = (hrefcb) => {
                //     if (hrefcb) {
                //         isEnd = hrefcb;
                //     } else {
                //     }
                // };

                // usePlugin('h5Login', context, callback);

                let res;
                if (this.low) {
                    const params = {
                        url: `/api/system/login`,
                        data: {
                            UserName: AccountId,
                            Password: AES_ECB_encrypt(AccountPassword),
                            LoginType,
                            TenantName: this.tenantName,
                        },
                        headers: {
                            Env: this.env,
                        },
                    };

                    res = await localService.login(params);
                    const { authorization } = res.headers;
                    const { userName, userId } = getObj(getObj(res).data).Data; // 制品返回的登录信息的结构
                    cookie.set({ authorization });
                    this.$emit('success', { Authorization: authorization, UserName: userName, UserId: userId, LoginType });
                    if (window.appVue && !this.$listeners.success) {
                        // if (window.appVue ) {
                        customLocation.href = this.indexPage;
                    }
                } else {
                    const params = {
                        url: this.nuimsUrl,
                        body: {
                            UserName: AccountId,
                            Password: AES_ECB_encrypt(AccountPassword),
                            // Password: AccountPassword,
                            LoginType,
                            TenantName: this.tenantName || getTenant(),
                            DomainName: NUIMS_DOMAIN_NAME,
                        },
                    };
                    const loginParams = {
                        url: this.nuimsUrl,
                        data: {
                            UserName: AccountId,
                            Password: AES_ECB_encrypt(AccountPassword),
                            LoginType,
                            TenantName: this.tenantName || getTenant(),
                            DomainName: NUIMS_DOMAIN_NAME,
                        },
                    };
                    if (this.env) {
                        params.headers = {
                            Env: this.env,
                        };
                        loginParams.headers = {
                            Env: this.env,
                        };
                    }
                    const isplugin = this.tabs.find((item) => item.value === LoginType)?.plugin;
                    const loginApi = isplugin ? service.NuimsLogin : service.login;
                    res = await loginApi(isplugin ? params : loginParams);
                    const { authorization } = res.headers;
                    const { UserName, UserId } = res.data.Data;
                    cookie.set({ authorization });
                    this.$emit('success', { Authorization: authorization, UserName, UserId, LoginType, AccountId, AccountPassword });
                    if (window.appVue && !this.$listeners.success) {
                        customLocation.href = this.indexPage;
                    }
                }
            } catch (error) {
                console.error('error: ', error);
                errMsg = error && error.message;
                if (error && error?.status === 404) {
                    errMsg = '接口不存在！';
                }
                if (
                    errMsg
                    === '参数错误，请检查如下请求参数: UserName or Password'
                ) {
                    errMsg = '请输入正确的账号或密码';
                }

                this.$toast.show({
                    message: errMsg,
                    position: 'top',
                });
                this.$emit('error', { Message: errMsg || 'login error' });
            }
            this.errMsg = errMsg;
        },
        // Auth 登录
        jumpAuth(type) {
            const { search } = location;
            const allLoginTypes = [...this.tabs, ...this.authTypes, ...this.redirectLoginTypes];
            const isplugin = allLoginTypes.find((item) => item.value === type)?.plugin;
            this.low = this.low || isplugin;
            let jumpHref;
            // 问题在这里  Test 不适用这条规则
            if (concatPluginList(['Taikang', 'Shufan', 'lowcode_aam']).includes(type)) {
                this.low = false;
                if (this.isProductApp && window?.appInfo?.hasUserCenter) {
                    this.low = true;
                }
            }
            // 制品下沉
            if (this.low) {
                // 下沉式在当前环境设置值，集中式不需要设置
                localStorage.setItem('compType', 'pass');
            }
            const { redirect = encodeURIComponent(location.href) } = queryString.parse(search);
            // 非下沉模式，需要跳转到 nuims 的集中登录
            let fnPassSrc = this.passSrc;

            if (type === 'Shufan') {
                fnPassSrc = this.passSrc.replace(/http(s)?:\/\/(dev\.)?/, 'https://');
                customLocation.href = `${this.low ? location.href : `${fnPassSrc}/pass`}?redirect=${redirect}&loginType=C${type}&env=${this.fnEnv}`;
                return;
            }
            // 工行生产环境去掉默认 defaulttenant
            if (type === 'lowcode_aam' && !fnPassSrc.includes('dev.defaulttenant.')) {
                fnPassSrc = fnPassSrc.replace('defaulttenant.', '');
            }
            const context = {
                query: queryString.parse(search),
                passSrc: this.passSrc,
                low: this.low,
                redirect,
                loginType: type,
                fnEnv: this.fnEnv,
            };
            const callback = (hrefcb) => {
                if (hrefcb) {
                    jumpHref = hrefcb;
                } else {
                    jumpHref = `${this.low ? location.href : `${fnPassSrc}/pass`}?redirect=${redirect}&loginType=C${type}`;
                }
            };

            usePlugin('h5BeforeJump', context, callback);
            customLocation.href = jumpHref || `${this.low ? location.href : `${fnPassSrc}/pass`}?redirect=${redirect}&loginType=C${type}`;
        },
        async getTenantConfigForPass() {
            // 跳转回来，页面刷新，这时候需要请求一次配置
            let AuthConfigMap = {};
            let res;
            if (this.low) {
                res = await localService.getTenantLoginTypes({
                });
                AuthConfigMap = getObj(getObj(getObj(res).data).Data);
            } else {
                res = await service.getTenantLoginTypes({
                    url: this.nuimsUrl,
                    params: { TenantName: this.tenantName || getTenant() },
                });
                getArr(getObj(res).data.Data).forEach((d) => {
                    const { LoginType } = getObj(d);
                    AuthConfigMap[LoginType] = [d];
                });
            }
            this.AuthConfigMap = AuthConfigMap;
        },
        async jumpAuthPass() {
            const allLoginTypes = [...this.tabs, ...this.authTypes, ...this.redirectLoginTypes];
            // 因为跳转回来之后，组件会刷新，所以配置信息需要载请求一次
            await this.getTenantConfigForPass();
            const { origin, search, pathname } = location;
            const query = queryString.parse(search);
            const { redirect, loginType } = query;
            const isplugin = allLoginTypes.find((item) => item.value === loginType.slice(1))?.plugin;
            if (redirect) {
                localStorage.setItem('From', redirect);
                cookie.set({ From: redirect });
            }
            if (this.low || isplugin) {
                localStorage.setItem('compType', 'cb');
            }

            const redirectUri = `${origin}${pathname}?redirect=${redirect}`;
            localStorage.setItem('LoginType', loginType);
            localStorage.setItem('RedirectUri', redirectUri);
            cookie.set({ RedirectUri: redirectUri, LoginType: loginType });

            let authUrl;
            switch (loginType) {
                case 'lowcode_aam':
                case 'Clowcode_aam':
                    // eslint-disable-next-line no-case-declarations
                    const { lowcode_aamAAMUrl, Version, Style, Op, OpMode, Lang, ServiceName } = this.AuthConfigMap.lowcode_aam;
                    authUrl = `${lowcode_aamAAMUrl}?${queryString.stringify({
                        SERVICENAME: ServiceName,
                        SERVICEURL: redirectUri,
                        VERSION: Version,
                        STYLE: Style,
                        OP: Op,
                        OPMode: OpMode,
                        lang: Lang,
                    })}`;
                    break;
            }
            if (this.isProductApp && this.low) {
                authUrl = this.AuthConfigMap[loginType.slice(1)].config.authPageUrl;
            } else {
                authUrl = this.AuthConfigMap[loginType.slice(1)][0]?.extendProperties?.authPageUrl;
            }

            const authObj = new URL(authUrl);
            const obj = queryString.parse(authObj.search);
            obj.redirect_uri = redirectUri;
            authObj.search = queryString.stringify(obj);
            if (loginType.slice(1) === 'lowcode_aam') {
                obj.SERVICEURL = redirectUri;
                authObj.search = queryString.stringify(obj);
                customLocation.href = authObj.toString();
            } else if (loginType.slice(1) === 'Shufan') {
                customLocation.href = `${authUrl}${redirectUri}`;
            }
            let jumpPassUrl;
            const context = {
                loginType: loginType.slice(1),
                low: this.low,
                redirectUri,
                query,
                queryString,
                authUrl,
                authUrlObj: authObj,
                authSearch: obj,
            };
            const callback = (hrefcb) => {
                if (hrefcb) {
                    jumpPassUrl = hrefcb;
                } else {
                    jumpPassUrl = decodeURIComponent(authObj.toString());
                }
            };
            usePlugin('h5JumpPass', context, callback);
            customLocation.href = jumpPassUrl || decodeURIComponent(authObj.toString());
        },
    },
};
</script>

