class Xuetong {
    constructor() {
        this.name = 'Xuetong';
        this.category = 'Sub';
    }

    h5JumpPass(context, callback) {
        const { query, authUrlObj, authSearch, queryString } = context;
        let corp;
        if (query?.redirect) {
            const r = new URL(query.redirect);
            if (r) {
                corp = r?.searchParams?.get('corp');
            }
        }
        if (corp) {
            authSearch.corp = corp;
        }
        // authSearch.corp = query.crop;
        authUrlObj.search = queryString.stringify(authSearch);
        const jumpPassUrl = decodeURIComponent(authUrlObj.toString());
        callback(jumpPassUrl);
    }

    h5BeforeJump(context, callback) {
        const { passSrc, redirect, low, loginType: type, fnEnv, query } = context;
        const fnPassSrc = passSrc;
        // .replace(/http(s)?:\/\/(dev\.)?/, 'https://');
        let href = `${low ? location.href : `${fnPassSrc}/pass`}?redirect=${redirect}&loginType=C${type}&env=${fnEnv}`;
        let corp;
        if (query?.redirect) {
            const r = new URL(query.redirect);
            if (r) {
                corp = r?.searchParams?.get('corp');
            }
        }
        if (corp) {
            href = `${href}&corp=${corp}`;
        }
        callback(href);
    }

    h5CodeLogin(context, callback) {
        const { query } = context;
        const params = {
            LoginType: 'Xuetong',
            ...query,
        };

        callback(params);
    }

    codeLogin(context, callback) {
        const { query } = context;
        const params = {
            LoginType: 'Xuetong',
            ...query,
        };

        callback(params);
    }

    h5NuimsCodeLogin(context, callback) {
        const { query } = context;
        const params = { body: { LoginType: 'Xuetong', ...query } };
        callback(params);
    }

    nuimsCodeLogin(context, callback) {
        const { query } = context;
        const params = { body: { LoginType: 'Xuetong', ...query } };
        callback(params);
    }
}
export default Xuetong;
